60	func (c *Controller) ListAISuites(ctx *gin.Context, clusterCode string) (*aisuite.ListAISuitesResp, error) {
61		suiteRegistry, err := getSuiteRegistry(c.db)
62		var aiSuitesInRegistry []*aisuite.ProfileAISuite
63		if err != nil {
64			log.Errorf("failed to get suite registry: %v", err)
65		} else {
66			aiSuitesInRegistry, err = listAISuitesInRegistry(ctx, suiteRegistry)
67			if err != nil {
68				log.Errorf("failed to list AI Suites in registry: %v", err)
69			}
70		}
71	
72		aiSuitesInCluster, err := c.listAISuitesInCluster(clusterCode)
73		// 如果查询集群内套件失败，应该直接返回报错，防止用户下一步操作部署一个已经在集群里部署了的套件（因为用户看不到集群里的套件列表，以为没有，所以又部署了一个）
74		if err != nil {
75			log.Errorf("failed to list AI Suites in cluster: %v", err)
76			return nil, fmt.Errorf("failed to list AI Suites in cluster: %w", err)
77		}
78	
79		// 入参底层数组可能会被修改，如果后面要增加逻辑，注意处理
80		aiSuites := disruptiveMergeAiSuites(aiSuitesInRegistry, aiSuitesInCluster)
81		sort.Slice(aiSuites, func(i, j int) bool {
82			return aiSuites[i].Name < aiSuites[j].Name
83		})
84		return &aisuite.ListAISuitesResp{
85			Total: len(aiSuites),
86			Data:  aiSuites,
87		}, nil
88	}
