166	func (c *Controller) OperateAISuiteInCluster(ctx *gin.Context, req *aisuite.OperateAISuiteReq) error {
167		if req.Action == ActionUninstall {
168			// 执行卸载操作
169			if err := c.uninstallAISuiteInCluster(req.ClusterCode, req.Name, req.Namespace); err != nil {
170				return fmt.Errorf("failed to uninstall AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
171			}
172			return nil
173		}
174	
175		switch req.Action {
176		case ActionInstall:
177			// 执行安装操作
178			if err := c.installAISuiteInCluster(req.ClusterCode, req.Name, req.ChartVersion, req.CustomValues); err != nil {
179				return fmt.Errorf("failed to install AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
180			}
181		case ActionUpgrade:
182			// 执行升级操作
183			if err := c.upgradeAISuiteInCluster(req.ClusterCode, req.Namespace, req.Name, req.ChartVersion, req.CustomValues); err != nil {
184				return fmt.Errorf("failed to upgrade AI Suite %s in cluster %s: %w", req.Name, req.ClusterCode, err)
185			}
186		default:
187			return fmt.Errorf("unsupported operation: %s", req.Action)
188		}
189		return nil
190	}
