345	func chartToProfileAISuite(chart *model.Artifact) *aisuite.ProfileAISuite {
346		simpleRepoName, _ := chart.ExtraAttrs["name"].(string)
347		chartVersion, _ := chart.ExtraAttrs["version"].(string)
348		appVersion, _ := chart.ExtraAttrs["appVersion"].(string)
349		if appVersion == "" {
350			appVersion = "devEdition"
351		}
352		displayVersion := getDisplayVersion(appVersion, chartVersion)
353		description, ok := chart.ExtraAttrs["description"].(string)
354		if !ok {
355			description = fmt.Sprintf("AI套件: %s:%s", simpleRepoName, displayVersion)
356		}
357	
358		return &aisuite.ProfileAISuite{
359			Name:        simpleRepoName,
360			Status:      deployStatusUndeployed,
361			Description: description,
362			Version: &aisuite.AISuiteVersion{
363				AppVersion:     appVersion,
364				ChartVersion:   chartVersion,
365				DisplayVersion: displayVersion,
366			},
367		}
368	}
